{
  "disease_related": [
    {
      "complication": "Metastatic disease",
      "management": "Systemic therapy with TKIs; surgery or interventional procedures for limited disease [GIST-4, GIST-5]. Liver and peritoneal metastases are most common; lymph node metastases are rare except in SDH-deficient GIST [MS-2]."
    },
    {
      "complication": "Tumor rupture or hemorrhage",
      "management": "Emergency surgery; considered as metastatic disease due to high recurrence risk [GIST-3, GIST-C]. Tumor rupture is a poor prognostic factor [v,52]."
    },
    {
      "complication": "GI obstruction or perforation",
      "management": "Surgical intervention [GIST-C]. May present as acute abdomen requiring immediate attention [MS-2]."
    }
  ],
  "treatment_related": {
    "chemotherapy": "GIST are generally resistant to conventional chemotherapy; no standard regimens are recommended [MS-2].",
    "immunotherapy": "Limited data; ipilimumab plus nivolumab is considered for tumor mutational burden-high (TMB-H) GIST [27].",
    "targeted_therapy": {
      "imatinib": "Common adverse events include fluid retention, diarrhea, nausea, fatigue, muscle cramps, abdominal pain, and rash. Serious toxicities: liver function test abnormalities (<5%), lung toxicity, neutropenia, GI bleeding, and cardiotoxicity (grade 3/4 in 8.2%) [59,60]. Management involves dose adjustments and supportive care.",
      "sunitinib": "Common toxicities: fatigue, nausea, vomiting, hematologic toxicities, diarrhea, hand-foot skin reaction (HFSR), hypertension, hypothyroidism, and cardiotoxicity. HFSR occurs in up to 20% of patients [65]; hypertension in 28% and hypothyroidism in 12% [68]. Management includes dose interruptions/reductions, emollients for HFSR, antihypertensives, and thyroid hormone replacement.",
      "regorafenib": "Similar TKI-related toxicities, with diarrhea, HFSR, and hypertension being common [88].",
      "ripretinib": "Common adverse events include alopecia, diarrhea, nausea, and fatigue; serious potential for secondary malignancies [117]."
    },
    "surgery": "Risks include tumor rupture, spillage, bleeding, infection, and anastomotic leak. Avoidance of pseudocapsule violation is critical. Minimally invasive approaches are selected for favorable locations [GIST-C, MS-4].",
    "radiation": "Palliative radiotherapy for symptomatic lesions, especially bone metastases; category 2B recommendation [GIST-5]. May cause local tissue damage."
  }
}
